class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def count_nodes(root):
    if not root:
        return 0
    count = 1
    queue = [root.left, root.right]
    while queue:
        node = queue.pop(0)
        if node:
            count += 1
            queue.append(node.left)
            queue.append(node.right)
    return count

class TestCountNodes:
    def test_single_node(self):
        assert count_nodes(TreeNode(5)) == 1

    def test_root_with_two_children(self):
        root = TreeNode(1, TreeNode(2), TreeNode(3))
        assert count_nodes(root) == 3

    def test_root_with_only_left_child(self):
        root = TreeNode(1, TreeNode(2))
        assert count_nodes(root) == 2

    def test_root_with_only_right_child(self):
        root = TreeNode(1, None, TreeNode(3))
        assert count_nodes(root) == 2

    def test_deep_tree(self):
        root = TreeNode(1, None, TreeNode(2, None, TreeNode(3)))
        assert count_nodes(root) == 3

    def test_full_binary_tree(self):
        root = TreeNode(1, 
                    TreeNode(2, TreeNode(4), TreeNode(5)), 
                    TreeNode(3))
        assert count_nodes(root) == 5

    def test_empty_tree(self):
        assert count_nodes(None) == 0

    def test_root_with_children_and_grandchildren(self):
        root = TreeNode(1, 
                    TreeNode(2), 
                    TreeNode(3, TreeNode(4), TreeNode(5)))
        assert count_nodes(root) == 5

    def test_root_with_left_child_and_grandchild(self):
        root = TreeNode(1, TreeNode(2, TreeNode(3)))
